mapper.select:
SELECT id, node_id, host, port, status, last_heartbeat_time, create_time, update_time
FROM scheduler_node
WHERE node_id = #{nodeId}

mapper.insert:
INSERT INTO scheduler_node (
    node_id, host, port, status, last_heartbeat_time, create_time, update_time
) VALUES (
    #{nodeId}, #{host}, #{port}, #{status}, #{lastHeartbeatTime}, NOW(), NOW()
)
